// Parse incoming Telegram update for Layer Info workflow
const body = $input.first().json;
let action = 'ignore';
let postId = '';
let chatId = '';

// 1. Handle callback_query: layer_info|PostID
if (body.callback_query) {
  const data = body.callback_query.data || '';
  if (data.startsWith('layer_info')) {
    action = 'prompt';
    postId = data.split('|')[1] || '';
    chatId = String(body.callback_query.message?.chat?.id || '');
  }
}

// 2. Handle text message: ALL or TEMPLATEINFO <PostID>
if (body.message && body.message.text) {
  const text = body.message.text.trim();
  const upper = text.toUpperCase();
  chatId = String(body.message.chat?.id || '');

  if (upper === 'ALL') {
    action = 'fetch';
    postId = '';
  } else if (upper.startsWith('TEMPLATEINFO')) {
    action = 'fetch';
    const parts = text.split(/\s+/);
    postId = parts[1] || '';
  }
}

return [{ json: { action, postId, chatId } }];

// ═══ BUILD LAYER DOCUMENT (HTML — bold/italic formatted) ═══
const routeData = $('Parse Layer Command1').first().json;
const postId = routeData.postId || '';
const chatId = routeData.chatId || '';
const mode = postId ? 'single' : 'all';

const cal = $('Read Calendar for Layers1').all().map(i => i.json);
const templates = $('Fetch Templates for Layers1').all().map(i => i.json);

// ── Filter posts ──
let posts = [];
if (mode === 'single') {
  const found = cal.find(r => r.PostID === postId);
  if (found) posts = [found];
} else {
  posts = cal.filter(r => r.PreferredTemplate || r['Preferred Template']);
}

if (posts.length === 0) {
  const errMsg = mode === 'single'
    ? `❌ Post ID \`${postId}\` not found or has no template assigned.`
    : '❌ No posts with templates found in the calendar.';
  return [{ json: { chatId, error: true, errorMsg: errMsg } }];
}

// ── Helper: strip template name suffixes ──
function getBaseName(name) {
  return name
    .replace(/\s*\(\s*page[-\s]*\d+\s*\)/gi, '')
    .replace(/\s*\(\s*slide[-\s]*\d+\s*\)/gi, '')
    .replace(/\s*\(\s*scene[-\s]*\d+\s*\)/gi, '')
    .replace(/\s*\(Id:[^)]+\)/i, '')
    .trim();
}

// ── Helper: find matching templates ──
function findTemplates(templateName, contentType, tplId) {
  const baseName = getBaseName(templateName);
  const baseNameLower = baseName.toLowerCase();
  let matched = [];

  if (contentType.includes('carousel')) {
    matched = templates.filter(t => {
      const tName = (t.title || t.name || '').trim().toLowerCase();
      return tName.startsWith(baseNameLower);
    });
  } else if (contentType.includes('reel')) {
    const m = templates.find(t => {
      const tName = (t.title || t.name || '').trim().toLowerCase();
      return tName === baseNameLower || tName.startsWith(baseNameLower);
    });
    if (m) matched = [m];
  } else {
    if (tplId) {
      const m = templates.find(t => (t.uuid || t.id) === tplId);
      if (m) matched = [m];
    }
    if (matched.length === 0) {
      const m = templates.find(t => {
        const tName = (t.title || t.name || '').trim().toLowerCase();
        return tName === baseNameLower;
      });
      if (m) matched = [m];
    }
  }
  return matched;
}

// ── HTML helpers ──
const b  = (s) => `<b>${s}</b>`;
const i  = (s) => `<i>${s}</i>`;
const bi = (s) => `<b><i>${s}</i></b>`;
const code = (s) => `<code>${s}</code>`;
const hr  = () => `<hr style="border:none;border-top:1px solid #ccc;margin:10px 0;">`;
const div = (s, style='') => `<div${style ? ` style="${style}"` : ''}>${s}</div>`;

// ── Build HTML document ──
let html = `<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<style>
  body { font-family: Arial, sans-serif; font-size: 13px; color: #222; margin: 24px; line-height: 1.6; }
  h1 { font-size: 18px; color: #1a1a2e; margin-bottom: 4px; }
  h2 { font-size: 15px; color: #2c2c54; margin: 20px 0 4px; border-bottom: 2px solid #ddd; padding-bottom: 4px; }
  h3 { font-size: 13px; color: #3d3d80; margin: 14px 0 4px; }
  .meta { color: #888; font-size: 12px; margin-bottom: 16px; }
  .label-text  { background: #e8f4fd; padding: 2px 8px; border-radius: 4px; font-size: 12px; font-weight: bold; color: #1565c0; display: inline-block; margin-bottom: 4px; }
  .label-image { background: #fce8e6; padding: 2px 8px; border-radius: 4px; font-size: 12px; font-weight: bold; color: #b71c1c; display: inline-block; margin-bottom: 4px; }
  .layer-row { margin: 4px 0 4px 16px; }
  .url { color: #1a73e8; word-break: break-all; font-style: italic; font-size: 12px; }
  .cmd-box { background: #f5f5f5; border-left: 3px solid #aaa; padding: 6px 12px; margin: 8px 0; font-family: monospace; font-size: 12px; color: #333; }
  .warn { color: #c62828; font-weight: bold; }
  .slide-header { background: #f0f4ff; border-left: 3px solid #3949ab; padding: 4px 10px; margin: 10px 0 6px; font-weight: bold; font-size: 13px; color: #1a237e; }
  .post-block { border: 1px solid #ddd; border-radius: 6px; padding: 14px 18px; margin: 18px 0; background: #fafafa; }
  .tip { color: #555; font-size: 11px; font-style: italic; }
</style>
</head>
<body>
<h1>📋 Template Layer Info</h1>
<p class="meta"><i>Generated: ${new Date().toISOString().replace('T', ' ').substring(0, 19)}</i></p>
`;

const skipNames = ['vector shape', 'shape', 'vector', 'divider', 'line', 'decorator'];

for (const post of posts) {
  const pid          = post.PostID || '';
  const contentType  = (post.ContentType || '').toLowerCase().replace(/\s+/g, '_');
  const templateName = post.PreferredTemplate || post['Preferred Template'] || '';
  const tplId        = post.PreferredTemplateId || '';
  const layerUrlsRaw = post.Layer_URLs || '{}';
  let existingUrls   = {};
  try { existingUrls = JSON.parse(layerUrlsRaw); } catch(e) {}

  const matched = findTemplates(templateName, contentType, tplId);

  html += `<div class="post-block">`;
  html += `<h2>📌 POST: ${b(pid)} <span style="font-weight:normal;font-size:12px;color:#666;">(${contentType || 'unknown'})</span></h2>`;
  html += `<p>🎨 ${b('Template:')} ${i(templateName || '(none)')}</p>`;

  // ── Render layers for a single template ──
  function renderLayers(layers, urlMap) {
    const textL = [], imgL = [];
    for (const layer of (layers || [])) {
      const nm = layer.name || '';
      if (skipNames.some(sk => nm.toLowerCase().includes(sk))) continue;
      if (layer.type === 'text' || layer.type === 'textbox') {
        const cm = nm.match(/\(Chars:(\d+)\)/i);
        textL.push({ name: nm, max: cm ? parseInt(cm[1]) : null });
      } else if (layer.type === 'picture' || layer.type === 'image') {
        imgL.push({ name: nm, url: urlMap[nm] || '(none)' });
      }
    }
    let out = '';
    if (textL.length) {
      out += `<span class="label-text">TEXT LAYERS</span>`;
      textL.forEach((l, idx) => {
        out += `<div class="layer-row">${idx + 1}. ${b(l.name)}`;
        if (l.max) out += ` ${i(`(max ${l.max} chars)`)}`;
        out += `</div>`;
      });
    }
    if (imgL.length) {
      out += `<span class="label-image">IMAGE LAYERS</span>`;
      imgL.forEach((l, idx) => {
        out += `<div class="layer-row">${idx + 1}. ${b(l.name)}<br>`;
        out += `&nbsp;&nbsp;&nbsp;Current URL: <span class="url">${l.url}</span></div>`;
      });
    }
    return out;
  }

  if (matched.length === 0) {
    html += `<p class="warn">⚠️ No matching Placid template found!</p>`;

  } else if (contentType.includes('carousel')) {
    const sorted = matched.map(t => {
      const tName = (t.title || t.name || '').trim();
      const pm    = tName.match(/\(\s*(?:page|slide)[-\s]*(\d+)\s*\)/i);
      return { template: t, pageNum: pm ? parseInt(pm[1]) : 999, tName };
    }).sort((a, b) => a.pageNum - b.pageNum);

    for (const s of sorted) {
      html += `<div class="slide-header">SLIDE ${s.pageNum}: ${s.tName}</div>`;
      html += renderLayers(s.template.layers, existingUrls);
    }

  } else if (contentType.includes('reel')) {
    const allLayers = matched[0].layers || [];
    const pages     = {};
    for (const layer of allLayers) {
      const nm = layer.name || '';
      if (skipNames.some(sk => nm.toLowerCase().includes(sk))) continue;
      const pm = nm.toLowerCase().match(/page[-\s]*(\d+)/i);
      const pn = pm ? parseInt(pm[1]) : 0;
      if (!pages[pn]) pages[pn] = [];
      pages[pn].push(layer);
    }
    for (const p of Object.keys(pages).map(Number).sort((a, b) => a - b)) {
      const label = p === 0 ? 'GLOBAL LAYERS' : `SCENE ${p}`;
      html += `<div class="slide-header">${label}</div>`;
      html += renderLayers(pages[p], existingUrls);
    }

  } else {
    html += renderLayers(matched[0].layers, existingUrls);
  }

  // ── Edit commands ──
  html += `<h3>📝 Edit Commands</h3>`;
  html += `<div class="cmd-box">`;
  if (contentType.includes('carousel')) {
    html += `${b('IMAGE')} ${pid} SLIDE N LAYER N ${i('&lt;url&gt;')}<br>`;
    html += `${b('TEXT')} ${pid} SLIDE N ${i('&lt;new text&gt;')}`;
  } else if (contentType.includes('reel')) {
    html += `${b('IMAGE')} ${pid} SCENE N LAYER N ${i('&lt;url&gt;')}<br>`;
    html += `${b('TEXT')} ${pid} SCENE N ${i('&lt;new text&gt;')}`;
  } else {
    html += `${b('IMAGE')} ${pid} ${i('&lt;url&gt;')}<br>`;
    html += `${b('TEXT')} ${pid} ${i('&lt;new text&gt;')}`;
  }
  html += `</div>`;
  html += `<p class="tip">💡 Use the ${b('exact layer names')} shown above when editing.</p>`;
  html += `</div>`;
}

html += `</body></html>`;

// ── Output as .html (Google Docs opens this with full formatting) ──
const fileName   = mode === 'single' ? `layer_info_${postId}.html` : 'layer_info_all_posts.html';
const fileBuffer = Buffer.from(html, 'utf-8');

return [{
  json: { chatId, fileName },
  binary: {
    data: {
      data: fileBuffer.toString('base64'),
      mimeType: 'text/html; charset=utf-8',
      fileName,
      fileExtension: 'html',
      fileSize: fileBuffer.length
    }
  }
}];
